
import React, { useState } from "react";
import { Recycle, ArrowDown, Info } from "lucide-react";
import { Button } from "@/components/ui/button";
import Navbar from "@/components/Navbar";
import ImageUpload from "@/components/ImageUpload";
import WasteResult from "@/components/WasteResult";
import WasteCategories from "@/components/WasteCategories";
import { analyzeWasteImage, WasteResult as WasteResultType } from "@/utils/wasteAnalyzer";
import AnimatedContainer from "@/components/AnimatedContainer";
import { useToast } from "@/components/ui/use-toast";

const Index = () => {
  const [selectedImage, setSelectedImage] = useState<File | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<WasteResultType | null>(null);
  const { toast } = useToast();

  const handleImageSelected = (file: File) => {
    setSelectedImage(file);
    setResult(null);
  };

  const handleAnalyze = async () => {
    if (!selectedImage) {
      toast({
        title: "No image selected",
        description: "Please upload an image to analyze.",
        variant: "destructive",
      });
      return;
    }

    setIsAnalyzing(true);
    
    try {
      const wasteResult = await analyzeWasteImage(selectedImage);
      setResult(wasteResult);
      
      // Scroll to result after a short delay to allow for animation
      setTimeout(() => {
        document.getElementById("result-section")?.scrollIntoView({
          behavior: "smooth",
          block: "center",
        });
      }, 300);
    } catch (error) {
      console.error("Error analyzing image:", error);
      toast({
        title: "Analysis failed",
        description: "There was a problem analyzing your image. Please try again.",
        variant: "destructive",
      });
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="min-h-screen">
      <Navbar />
      
      {/* Hero Section */}
      <section className="relative pt-32 pb-20 overflow-hidden">
        <div className="absolute inset-0 z-0 pointer-events-none">
          <div className="absolute top-0 left-0 right-0 h-96 bg-gradient-to-b from-primary/5 to-transparent" />
          <div className="absolute -top-40 -right-40 w-80 h-80 rounded-full bg-primary/10 blur-3xl opacity-70" />
          <div className="absolute -bottom-20 -left-20 w-60 h-60 rounded-full bg-primary/10 blur-3xl opacity-50" />
        </div>
        
        <div className="container relative z-10 mx-auto px-4">
          <AnimatedContainer className="max-w-2xl mx-auto text-center" animationType="fade">
            {/* <span className="inline-block px-3 py-1 bg-primary/10 text-primary rounded-full text-sm font-medium mb-3">
              Waste Sorting Made Simple
            </span> */}
            <h1 className="text-4xl md:text-5xl font-bold mb-6 tracking-tight">
            Automated Waste Segregation <span className="text-primary">Using Neural Networks</span>
            </h1>
            <p className="text-xl text-muted-foreground mb-8 max-w-xl mx-auto">
              Upload a photo of your waste item and get instant sorting instructions to help
              reduce landfill waste and improve recycling.
            </p>
            
            <Button
              size="lg"
              className="rounded-full gap-2 animate-pulse-subtle animate-delay-500"
              onClick={() => {
                document.getElementById("upload-section")?.scrollIntoView({
                  behavior: "smooth",
                });
              }}
            >
              <Recycle className="h-5 w-5" /> Get Started
            </Button>
          </AnimatedContainer>
          
          <div className="flex justify-center mt-12 md:mt-20">
            <AnimatedContainer
              animationType="slide-up"
              delay={500}
              className="animate-float"
            >
              <ArrowDown className="h-10 w-10 text-primary/50" />
            </AnimatedContainer>
          </div>
        </div>
      </section>
      
      {/* Upload Section */}
      <section
        id="upload-section"
        className="py-16 bg-gradient-to-b from-white to-waste-background"
      >
        <div className="container mx-auto px-4">
          <AnimatedContainer animationType="fade">
            <h2 className="text-3xl font-bold mb-8 text-center">
              Upload Your Waste Item
            </h2>
          </AnimatedContainer>
          
          <div className="max-w-2xl mx-auto">
            <ImageUpload onImageSelected={handleImageSelected} />
            
            <AnimatedContainer
              animationType="fade"
              delay={200}
              className="mt-6 text-center"
            >
              <Button
                size="lg"
                disabled={!selectedImage || isAnalyzing}
                onClick={handleAnalyze}
                className="relative overflow-hidden group"
              >
                <span className="relative z-10 flex items-center gap-2">
                  {isAnalyzing ? (
                    <>
                      <div className="h-4 w-4 rounded-full border-2 border-white/30 border-t-white animate-spin" />
                      Analyzing...
                    </>
                  ) : (
                    <>
                      <Recycle className="h-5 w-5" />
                      Analyze Waste
                    </>
                  )}
                </span>
                <span className="absolute inset-0 bg-primary/20 transform -translate-x-full group-hover:translate-x-0 transition-transform duration-300" />
              </Button>
            </AnimatedContainer>
          </div>
        </div>
      </section>
      
      {/* Result Section */}
      {(result || isAnalyzing) && (
        <section id="result-section" className="py-16 bg-waste-background">
          <div className="container mx-auto px-4">
            <AnimatedContainer animationType="fade">
              <h2 className="text-3xl font-bold mb-8 text-center">
                Analysis Result
              </h2>
            </AnimatedContainer>
            
            <div className="max-w-2xl mx-auto">
              {isAnalyzing ? (
                <div className="flex flex-col items-center justify-center p-12 border border-border rounded-xl bg-background/50">
                  <div className="h-12 w-12 rounded-full border-4 border-primary/30 border-t-primary animate-spin mb-4" />
                  <p className="text-muted-foreground">Analyzing your waste image...</p>
                </div>
              ) : (
                result && <WasteResult result={result} />
              )}
            </div>
          </div>
        </section>
      )}
      
      {/* Categories Section */}
      <div className="container mx-auto px-4">
        <WasteCategories />
      </div>
      
      {/* About Section */}
      <section id="about" className="py-16 bg-gradient-to-b from-waste-background to-white">
        <div className="container mx-auto px-4">
          <div className="max-w-3xl mx-auto">
            <AnimatedContainer animationType="slide-up">
              <div className="text-center mb-10">
                <span className="inline-block px-3 py-1 bg-primary/10 text-primary rounded-full text-sm font-medium mb-3">
                  About Waste Ninja
                </span>
                <h2 className="text-3xl font-bold mb-3">Our Mission</h2>
                <p className="text-muted-foreground max-w-2xl mx-auto">
                  We're dedicated to simplifying waste management and promoting environmental sustainability
                  through innovative technology.
                </p>
              </div>
            </AnimatedContainer>
            
            <div className="bg-white rounded-xl p-6 shadow-sm border border-border/50">
              <div className="flex items-start gap-4 mb-4">
                <div className="h-10 w-10 rounded-full bg-primary/10 flex items-center justify-center flex-shrink-0">
                  <Info className="h-5 w-5 text-primary" />
                </div>
                <div>
                  <h3 className="text-lg font-medium mb-2">How It Works</h3>
                  <p className="text-muted-foreground mb-4">
                    Waste Ninja uses advanced image recognition to identify waste items and provide
                    proper disposal instructions. Our technology helps reduce contamination in recycling
                    streams and diverts waste from landfills.
                  </p>
                  <ul className="space-y-2 mb-4">
                    {[
                      "Upload a photo of your waste item",
                      "Our system analyzes and categorizes the item",
                      "Get instant sorting instructions",
                      "Dispose of your waste correctly"
                    ].map((step, i) => (
                      <AnimatedContainer
                        key={i}
                        delay={i * 100}
                        animationType="slide-up"
                      >
                        <li className="flex items-start gap-2">
                          <span className="flex-shrink-0 h-5 w-5 rounded-full bg-primary/10 flex items-center justify-center text-xs text-primary">
                            {i + 1}
                          </span>
                          <span className="text-sm">{step}</span>
                        </li>
                      </AnimatedContainer>
                    ))}
                  </ul>
                  <p className="text-sm text-muted-foreground">
                    Join us in our mission to create a cleaner planet through proper waste management.
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>
      
      {/* Footer */}
      <footer className="bg-white py-8 border-t border-border/50">
        <div className="container mx-auto px-4 text-center">
          <div className="flex items-center justify-center gap-2 mb-4">
            <Recycle className="h-5 w-5 text-primary" />
            <h2 className="text-lg font-medium">Waste Ninja</h2>
          </div>
          <p className="text-sm text-muted-foreground">
            &copy; {new Date().getFullYear()} Waste Ninja. All rights reserved.
          </p>
        </div>
      </footer>
    </div>
  );
};

export default Index;
